
/* Swipers */
const introSwiper = new Swiper(".intro__swiper", {
    slidesPerView: 1,
    spaceBetween: 10,
    effect: "fade",
    navigation: {
        nextEl: ".intro__swiper-button-next",
        prevEl: ".intro__swiper-button-prev",
    },

    scrollbar: {
        el: ".intro__swiper-scrollbar",
    },

    pagination: {
        el: '.intro__swiper-pagination',
        type: 'fraction',
    
        renderFraction: function (currentClass, totalClass) {
          return `
            <span class="${currentClass}"></span>
            <span class="intro__swiper-pagination-text"></span>
          `;
        },
      },
    
      on: {
        init: function () {
          updateCustomPagination(this);
        },
        slideChange: function () {
          updateCustomPagination(this);
        },
      },
});

function updateCustomPagination(swiper) {
    const current = swiper.realIndex + 1;
    const activeSlide = swiper.slides[swiper.activeIndex];
    const titleEl = activeSlide.querySelector('.intro__title');
    const title = titleEl ? titleEl.textContent.trim() : '';
  
    const currentEl = swiper.pagination.el.querySelector('.swiper-pagination-current');
    const textEl = swiper.pagination.el.querySelector('.intro__swiper-pagination-text');
  
    if (currentEl) {
      currentEl.textContent = current + ' слайд';
    }
  
    if (textEl) {
      textEl.textContent = ` ${title}`;
    }
  }

